        //private static void MakeAntimicrobialReportsHeader(ClinicalDocument ccda, CCDADataModel objCcdaModel = null)
        private static void MakeAUPReportsHeader(ClinicalDocument ccda, CCDADataModel objCcdaModel = null)
        {
            MakeStaticSection(ccda, objCcdaModel);

            #region recordTarget
            if (objCcdaModel == null) return;
            RecordTarget rt = new RecordTarget
            {
                patientRole = new PatientRole
                {
                    id = new List<II> { new II { nullFlavor = "NA", } }
                }
            };
            ccda.recordTarget = new List<RecordTarget>
            {
                rt
            };
            #endregion recordTarget

            #region Author

            ccda.author = new List<Author>
            {
                new Author
                {
                    time = new TS
                    {
                        value = DateTime.Now.ToString("yyyyMMdd")
                    },
                    assignedAuthor=new AssignedAuthor
                    {
                        id=new List<II> { new II { root="2.16.840.1.113883.3.117.1.1.5.2.1.1",extension="aSoftwareID"}}
                    }

                }
            };
            #endregion Author

            #region custodian

            ccda.custodian = new Custodian
            {
                assignedCustodian = new AssignedCustodian
                {
                    representedCustodianOrganization = new CustodianOrganization
                    {
                        id = new List<II>
                        {
                            new II { root="2.16.840.1.114222.4.3.2.11"}
                        }
                    }
                }
            };

            #endregion custodian

            #region legalAuthenticator
            ccda.legalAuthenticator = new LegalAuthenticator
            {
                time = new TS
                {
                    value = DateTime.Now.ToString("yyyyMMdd")
                },
                signatureCode = new CS { code = "S" },
                assignedEntity = new AssignedEntity
                {
                    id = new List<II> { new II { root = "2.16.840.1.113883.3.117.1.1.5.1.1.2", extension = "aLegalAuthenticatorID" } }

                }

            };
            #endregion legalAuthenticator

            #region participant
            ccda.participant = new List<Participant1>
            {
                new Participant1
                {
                    typeCode="SBJ",
                    contextControlCode="OP",
                    associatedEntity=new AssociatedEntity
                    {
                        classCode="PRS",
                        code =new CE
                        {
                            codeSystem="2.16.840.1.113883.6.96", code="389109008", displayName="group"
                        }
                     }
                },
                new Participant1
                {
                    typeCode="LOC",
                    contextControlCode="OP",
                    associatedEntity=new AssociatedEntity
                    {
                        classCode="SDLOC",
