        private static void MakeAROReportsHeader(ClinicalDocument ccda, CCDADataModel objCcdaModel = null)
        {
            MakeStaticSection(ccda, objCcdaModel);

            #region recordTarget
            if (objCcdaModel == null) return;
            RecordTarget rt = new RecordTarget
            {
                patientRole = new PatientRole
                {
                    id = new List<II> {
                    new II {root="2.111.111.111.10009.1", extension="StAur-Bld_0902p" },
                    new II {root="2.111.111.111.10009.1", extension="2nd id" },
                    },
                }
            };
            if (objCcdaModel.lstPatientData != null && objCcdaModel.lstPatientData.Count > 0)
            {
                MakePatientNode(rt.patientRole, objCcdaModel.lstPatientData[0], objCcdaModel.lstRaceCodes, objCcdaModel.lstEthnicityCodes);
            }
            ccda.recordTarget = new List<RecordTarget>
            {
                rt
            };
            #endregion recordTarget

            #region Author

            ccda.author = new List<Author>
            {
                new Author
                {
                    time = new TS
                    {
                        value = DateTime.Now.ToString("yyyyMMdd")
                    },
                    assignedAuthor=new AssignedAuthor
                    {
                        id=new List<II> { new II { root="2.16.840.1.113883.3.117.1.1.5.2.1.1",extension="aSoftwareID"}}
                    }

                }
            };
            #endregion Author

            #region custodian

            ccda.custodian = new Custodian
            {
                assignedCustodian = new AssignedCustodian
                {
                    representedCustodianOrganization = new CustodianOrganization
                    {
                        id = new List<II>
                        {
                            new II { root="2.16.840.1.114222.4.3.2.11"}
                        }
                    }
                }
            };

            #endregion custodian

            #region legalAuthenticator
            ccda.legalAuthenticator = new LegalAuthenticator
            {
                time = new TS
                {
                    value = DateTime.Now.ToString("yyyyMMdd")
                },
                signatureCode = new CS { code = "S" },
                assignedEntity = new AssignedEntity
                {
                    id = new List<II> { new II { root = "2.16.840.1.113883.3.117.1.1.5.1.1.2", extension = "aLegalAuthenticatorID" } }

                }

            };
            #endregion legalAuthenticator

            #region ComponentOf

            var componentOf = new Component1();

            var encounter = new EncompassingEncounter
            {
                code = new CE
                {
                    codeSystem = "2.16.840.1.113883.5.4",
                    codeSystemName = "actEncounterCode",
                    code = "IMP",
                    displayName = "Inpatient"
                },
            };
            var loc = new Location
            {
                healthCareFacility = new HealthCareFacility
                {
                    id = new List<II> { new II { root = "2.111.111.111.10009" } },
                }
            };
            encounter.location = loc;
            encounter.id = new List<II> { new II { root = StaticCcdaData["UniqueIdentifierID"] } };
            var specimendate = objCcdaModel.lstAROOrganizm.Count() > 0 ? objCcdaModel.lstAROOrganizm[0]["DateSpecimenCollected"] : DateTime.Now.ToShortDateString();

            var high = Convert.ToDateTime(specimendate);
            encounter.effectiveTime = new IVL_TS
            {
                ItemsElementName = new[]
                {
                    ItemsChoiceType2.low,
                    ItemsChoiceType2.high
                },
                Items = new QTY[]
                {
                    new IVXB_TS { value = HelperMethods.SetDateTime(high) },
                    new IVXB_TS { value = HelperMethods.SetDateTime(high) }
                }
            };

            componentOf.encompassingEncounter = encounter;
            ccda.componentOf = componentOf;
            #endregion ComponentOf

        }
        private static HealthCareFacility MakeHealthCareFacility(CCDADataModel objCcdaModel = null)
        {
            var hcf = new HealthCareFacility();
            if (objCcdaModel == null || objCcdaModel.lstPracticeData.Count <= 0) return hcf;
            var objPracticeData = objCcdaModel.lstPracticeData[0];
            hcf.id = new List<II>
            {
                new II { root = StaticCcdaData["ProviderOrganizationID"] }
            };
            hcf.location = new Place();
            var facilityName = objCcdaModel.lstPatientData[0]["FacilityName"];
            if (!string.IsNullOrWhiteSpace(facilityName))
            {
                hcf.location.name = new ON
                {
                    Text = new List<string> { facilityName }
                };
            }
            hcf.location.addr = HelperMethods.SetAddress("WP",
                new List<string> { objPracticeData["Address"] },
                objPracticeData["City"], objPracticeData["State"], objPracticeData["ZIPCode"], "US");
            hcf.serviceProviderOrganization = new Organization
            {
                id = DocumentTemplate == DocumentTemplateType.CancerReport == true ?
                new List<II>
                {
                    new II {root = StaticCcdaData["ProviderOrganizationID"], extension ="77777777777"}
                } :
                new List<II>
                {
                    new II {root = StaticCcdaData["ProviderOrganizationID"]}
                },
                telecom = new List<TEL>
                {
                    HelperMethods.SetTelephone(objCcdaModel.lstPracticeData[0]["PhoneNo"], "WP",
                        objCcdaModel.lstPracticeData[0]["PhoneExt"])
                },
                addr = DocumentTemplate == DocumentTemplateType.CancerReport == true ?
                new List<AD>
                {
                    HelperMethods.SetAddressWithAddress("WP",
                        new List<string> {objPracticeData["Address"]},
                        objPracticeData["City"], objPracticeData["State"], objPracticeData["ZIPCode"], "US")
                } :
                new List<AD>
                {
                    HelperMethods.SetAddress("WP",
                        new List<string> {objPracticeData["Address"]},
                        objPracticeData["City"], objPracticeData["State"], objPracticeData["ZIPCode"], "US")
                }
            };
            return hcf;
        }

