        private static HealthCareFacility MakeHealthCareFacilityHS(CCDADataModel objCcdaModel = null)
        {
            var hcf = new HealthCareFacility();
            if (objCcdaModel == null || objCcdaModel.lstPatientData.Count <= 0) return hcf;
            var objPatient = objCcdaModel.lstPatientData[0];
            if (string.IsNullOrWhiteSpace(objPatient["FacilityLocation"]))
            {
                hcf.code = new CE
                {
                    nullFlavor = "NI"
                };
            }
            else
            {
                hcf.code = new CE
                {
                    code = objPatient["FacilityId"],
                    displayName = objPatient["FacilityLocation"],
                    codeSystem = "2.16.840.1.113883.6.259",
                    codeSystemName = "HL7 HealthcareServiceLocation"
                };
            }
            return hcf;
        }
