        public static void MakeStaticSection(ClinicalDocument ccda, CCDADataModel objCCDAModel)
        {
            ccda.realmCode = new List<CS>
            {
                new CS { code = StaticCcdaData["RealmCode"] }
            };
            ccda.typeId = new InfrastructureRoottypeId
            {
                root = StaticCcdaData["ClinicalDocumentTypeIdRoot"],
                extension = StaticCcdaData["ClinicalDocumentTypeIdExtension"]
            };

            if (DocumentTemplate == DocumentTemplateType.HealthCareSurveys || DocumentTemplate == DocumentTemplateType.CarePlan)
            {
                ccda.templateId = new List<II>();
                ccda.id = new II
                {
                    root = StaticCcdaData["UniqueIdentifierID"]
                };
            }
            else if (DocumentTemplate == DocumentTemplateType.AROReport || DocumentTemplate == DocumentTemplateType.AUPReport)
            {
                ccda.templateId = new List<II>();
                ccda.id = new II
                {
                    root = "2.16.840.1.113883.3.117.1.1.5.2.1.1.2",
                    extension = "20202201"
                };
            }
            else if (DocumentTemplate == DocumentTemplateType.CancerReport)
            {
                ccda.templateId = new List<II>
                {
                    new II { root = StaticCcdaData["TemplateID"],extension="2014-06-09" },
                    new II { root = "2.16.840.1.113883.10.13.1", extension="2015-01-29" },
                };
                ccda.id = new II
                {
                    root = StaticCcdaData["UniqueIdentifierID"],
                    extension = "TT988"
                };
                ccda.setId = new II
                {
                    root = "2.16.840.1.113883.19.5.99999.19",
                    extension = "sTT988"
                };
            }
            else
            {
                ccda.templateId = new List<II>
                {
                    new II { root = StaticCcdaData["TemplateID"],extension="2015-08-01" },
                };
                ccda.id = new II
                {
                    root = StaticCcdaData["UniqueIdentifierID"]
                };
            }
            ccda.code = new CE()
            {
                codeSystem = StaticCcdaData["ClinicalDocumentCodeCodeSystem"],
                codeSystemName = StaticCcdaData["ClinicalDocumentCodeCodeSystemName"],
                code = StaticCcdaData["ClinicalDocumentCodeCode"]
            };
            switch (DocumentTemplate)
            {
                case DocumentTemplateType.DataPortability:
                    ccda.templateId.Add(new II { root = StaticCcdaData["CS"], extension = "2015-08-01" });
                    ccda.templateId.Add(new II { root = StaticCcdaData["CS"] });
                    ccda.code.code = "34133-9";
                    ccda.code.displayName = "Transition of Care/Referral Summary";
                    ccda.title = new ST { Text = new List<string> { "Transition of Care/Referral Summary" } };
                    break;
                case DocumentTemplateType.ClinicalSummary:
                    ccda.templateId.Add(new II { root = StaticCcdaData["CS"], extension = "2015-08-01" });
                    ccda.templateId.Add(new II { root = StaticCcdaData["CS"] });
                    ccda.code.code = "34133-9";
                    ccda.code.displayName = "Summarization Of Episode Note";
                    ccda.title = new ST { Text = new List<string> { "Clinical Summary" } };
                    break;
                case DocumentTemplateType.ReferralSummary:
                    ccda.templateId.Add(new II { root = StaticCcdaData["CS"], extension = "2015-08-01" });
                    ccda.templateId.Add(new II { root = StaticCcdaData["CS"] });
                    ccda.code.code = "34133-9";
                    ccda.code.displayName = "Summarization Of Episode Note";
                    ccda.title = new ST { Text = new List<string> { "Transitions of Care" } };
                    break;
                case DocumentTemplateType.ReferralNote:
                    ccda.templateId.Add(new II { root = "2.16.840.1.113883.10.20.22.1.14", extension = "2015-08-01" });
                    ccda.templateId.Add(new II { root = "2.16.840.1.113883.10.20.22.1.14" });
                    ccda.code.code = "57133-1";
                    ccda.code.displayName = "Referral Note";
                    ccda.title = new ST { Text = new List<string> { "Referral Note" } };
                    break;
                case DocumentTemplateType.ContinutyofCaredocument:
                    ccda.templateId.Add(new II { root = StaticCcdaData["CS"], extension = "2015-08-01" });
                    ccda.templateId.Add(new II { root = StaticCcdaData["CS"] });
                    ccda.code.code = "34133-9";
                    ccda.code.displayName = "Continuity of Care Document";
                    ccda.title = new ST { Text = new List<string> { "Continuity of Care Document" } };
                    break;
                case DocumentTemplateType.CarePlan:
                    ccda.templateId.Add(new II { root = StaticCcdaData["TemplateID"], extension = "2015-08-01" });
                    ccda.templateId.Add(new II { root = StaticCcdaData["CP"], extension = "2015-08-01" });
                    ccda.code.code = "52521-2";
                    ccda.code.displayName = "Overall Plan of Care/Advance Care Directives";
                    ccda.title = new ST { Text = new List<string> { "Care Plan" } };
                    break;
                case DocumentTemplateType.AROReport:
