                    ccda.code.displayName = "Healthcare Associated Infection Report";
                    ccda.title = new ST { Text = new List<string> { "Denominator for Antimicrobial Resistance Option (ARO)" } };
                    ccda.setId = new II
                    {
                        root = "2.16.840.1.113883.3.117.1.1.5.2.1.1.5",
                        extension = "AntiP25-StAurBld_0902",
                    };
                    ccda.versionNumber = new INT { value = "1" };
