                    ccda.templateId.Add(new II { root = "2.16.840.1.113883.10.20.5.44" });
                    ccda.code.code = "51897-7";
                    ccda.code.displayName = "Healthcare Associated Infection Report";
                    ccda.title = new ST { Text = new List<string> { "Antimicrobial Use, Pharmacy Option (AUP) Summary Report" } };
                    ccda.setId = new II
                    {
                        root = "2.16.840.1.113883.3.117.1.1.5.2.1.1.1",
                        extension = "AR-Nov2014_0919",
