        public static void MakePatientRoleNode(RecordTarget rt, CCDADataModel objCcdaModel)
        {
            PatientRole pr = new PatientRole();
            List<Dictionary<string, string>> lstPatientData = objCcdaModel.lstPatientData;
            if (lstPatientData != null && lstPatientData.Count > 0)
            {
                Dictionary<string, string> patientData = lstPatientData[0];

                if (DocumentTemplate == DocumentTemplateType.HealthCareSurveys)
                {
                    pr.id = new List<II>
                    {
                        //new II { root =  StaticCcdaData["UniqueIdentifierID"] },
                        new II { root="2.16.840.1.113883.4.1", extension=patientData["PatientSSN"] },
                        new II { root="2.16.840.1.113883.4.572", extension=patientData["MRNumber"] },
                    };

                    pr.addr = new List<AD>
                    {
                        HelperMethods.SetAddress("HP", new List<string>() { patientData["PatientStreetAddress"], }, patientData["PatientCity"], patientData["PatientState"], patientData["PatientZIPCode"], "US")
                    };
                }
                else if (DocumentTemplate == DocumentTemplateType.CancerReport)
                {
                    pr.id = new List<II>
                    {
                        new II { root="2.16.840.1.113883.4.1", extension="444-22-2222" },
                        new II { root="2.16.840.1.113883.19", extension="325941988" },
                    };

                    pr.addr = new List<AD>
                    {
                        HelperMethods.SetAddressWithAddress("HP", new List<string>() { patientData["PatientStreetAddress"], }, patientData["PatientCity"], patientData["PatientState"], patientData["PatientZIPCode"], "US")
                    };
                }
                else
                {
                    pr.id = new List<II>
                    {
                        new II { root =  StaticCcdaData["UniqueIdentifierID"] }
                    };

                    pr.addr = new List<AD>
                    {
                        HelperMethods.SetAddress("H", new List<string>() { patientData["PatientStreetAddress"], }, patientData["PatientCity"], patientData["PatientState"], patientData["PatientZIPCode"], "US")
                    };
                }

                pr.telecom = new List<TEL>
                {
                    HelperMethods.SetTelephone(patientData["PatientHomePhoneNo"], "HP"),
                    HelperMethods.SetTelephone(patientData["PatientWorkPhoneNo"], "WP",
                        patientData["PatientWorkPhoneExt"])
                };

                MakePatientNode(pr, patientData, objCcdaModel.lstRaceCodes, objCcdaModel.lstEthnicityCodes);
                var pOrg = new Organization
                {
                    id = new List<II>
                    {
                        new II {root = StaticCcdaData["ProviderOrganizationID"]}
                    }
                };

                if (DocumentTemplate != DocumentTemplateType.HealthCareSurveys && DocumentTemplate != DocumentTemplateType.CancerReport)
                {
                    var practiceData = objCcdaModel.lstPracticeData[0];
                    var providerOrganization = practiceData["ShortName"];
                    if (string.IsNullOrWhiteSpace(providerOrganization))
                    {
                    }
                    else
                    {
                        pOrg.name = new List<ON>
                    {
                        new ON {Text = new List<string> {providerOrganization}}
                    };
                    }
                    pOrg.telecom = new List<TEL>
                    {
                        HelperMethods.SetTelephone(practiceData["PhoneNo"], "WP")
                    };
                    pOrg.addr = new List<AD>
                    {
                        HelperMethods.SetAddress("WP", new List<string>() { practiceData["Address"] }, practiceData["City"], practiceData["State"], practiceData["ZIPCode"], "US")
                    };
                    pr.providerOrganization = pOrg;

                }
                if (DocumentTemplate == DocumentTemplateType.CancerReport)
                {
                    var practiceData = objCcdaModel.lstPracticeData[0];
                    var providerOrganization = practiceData["ShortName"];
                    if (string.IsNullOrWhiteSpace(providerOrganization))
                    {
                    }
                    else
                    {
                        pOrg.name = new List<ON>
                    {
                        new ON {Text = new List<string> {providerOrganization}}
                    };
                    }
                    pOrg.telecom = new List<TEL>
                    {
                        HelperMethods.SetTelephone(practiceData["PhoneNo"], "WP")
                    };
                    pOrg.addr = new List<AD>
                    {
                        HelperMethods.SetAddressWithAddress("WP", new List<string>() { practiceData["Address"] }, practiceData["City"], practiceData["State"], practiceData["ZIPCode"], "US")
                    };
                    pr.providerOrganization = pOrg;

                }
            }
            rt.patientRole = pr;
        }

        public static void MakePatientRoleNodeCancer(RecordTarget rt, CCDADataModel objCcdaModel)
        {
            PatientRole pr = new PatientRole();
            List<Dictionary<string, string>> lstPatientData = objCcdaModel.lstPatientData;
            if (lstPatientData != null && lstPatientData.Count > 0)
            {
                Dictionary<string, string> patientData = lstPatientData[0];

                pr.id = !string.IsNullOrWhiteSpace(patientData["PatientSSN"]) == true ?
                    new List<II>
                    {
                        new II { root="2.16.840.1.113883.4.1", extension=patientData["PatientSSN"] },
                        new II { root="2.16.840.1.113883.4.572", extension=patientData["MRNumber"] },
                    } :
                    new List<II>
                    {
                        new II { root="2.16.840.1.113883.4.1", nullFlavor = "UNK" },
                        new II { root="2.16.840.1.113883.4.572", extension=patientData["MRNumber"] },
                    };

                pr.addr = new List<AD>
                    {
                        HelperMethods.SetAddressWithAddress("HP", new List<string>() { patientData["PatientStreetAddress"], }, patientData["PatientCity"], patientData["PatientState"], patientData["PatientZIPCode"], "US")
                    };

                pr.telecom = new List<TEL>
                {
                    HelperMethods.SetTelephone(patientData["PatientHomePhoneNo"], "HP"),
                    HelperMethods.SetTelephone(patientData["PatientWorkPhoneNo"], "WP",
                        patientData["PatientWorkPhoneExt"])
                };

                MakePatientNodeCancer(pr, patientData, objCcdaModel.lstRaceCodes, objCcdaModel.lstEthnicityCodes);
                var pOrg = new Organization
                {
                    id = new List<II>
                    {
                        new II {root = StaticCcdaData["ProviderOrganizationID"]}
                    }
                };

                var practiceData = objCcdaModel.lstPracticeData[0];
                var providerOrganization = practiceData["ShortName"];
                pOrg.id = new List<II>
                {
                    new II {extension="88888888", root="2.16.840.1.113883.4.6" },
                    new II { extension="219BX", root="1.1.1.1.1.1.1.1.2"}
                };
                if (string.IsNullOrWhiteSpace(providerOrganization))
                {
                }
                else
                {
                    pOrg.name = new List<ON>
                    {
                        new ON {Text = new List<string> {providerOrganization}}
                    };
                }
                pOrg.telecom = new List<TEL>
                    {
                        HelperMethods.SetTelephone(practiceData["PhoneNo"], "WP")
                    };
                pOrg.addr = new List<AD>
                    {
                        HelperMethods.SetAddressWithAddress("WP", new List<string>() { practiceData["Address"] }, practiceData["City"], practiceData["State"], practiceData["ZIPCode"], "US")
                    };
                pr.providerOrganization = pOrg;

            }
            rt.patientRole = pr;
        }



        public static void MakePatientNode(PatientRole pr, Dictionary<string, string> patientData, List<Dictionary<string, string>> lstRaceCodes, List<Dictionary<string, string>> lstEthnicityCodes)
        {
            var p = new Patient
            {
                name = new List<PN>
                {
                    HelperMethods.SetName("L", patientData["LastName"],
                        new List<string> {patientData["FirstName"], patientData["MI"]},"",patientData["Suffix"]),
                    !string.IsNullOrWhiteSpace(patientData["PreviousName"])?  HelperMethods.SetName("L", patientData["LastName"],
                        new List<string> {patientData["PreviousName"], patientData["MI"]},"",patientData["Suffix"],"1"):null
                },

                administrativeGenderCode = new CE
                {
                    code = HelperMethods.GetGenderCode(patientData["PatientGender"]),
                    codeSystem = StaticCcdaData["GenderCodeCodeSystem"],
                    codeSystemName = StaticCcdaData["GenderCodeCodeSystemName"],
                    displayName = patientData["PatientGender"]
                }
            };
            var dob = MDVUtility.ToDateTime(patientData["PatientDOB"]);
            p.birthTime = new TS
            {
                value = dob.ToString("yyyyMMdd")
            };
            p.maritalStatusCode = new CE();
            var maritalStatus = HelperMethods.GetMaritalStatusCode(patientData["MaritialStatus"]);
            if (string.IsNullOrEmpty(maritalStatus))
            {
                p.maritalStatusCode.nullFlavor = "NAV";
            }
            else
            {
                p.maritalStatusCode.code = HelperMethods.GetMaritalStatusCode(patientData["MaritialStatus"]);
                p.maritalStatusCode.codeSystem = StaticCcdaData["MaritalStatusCodeSystem"];
                p.maritalStatusCode.codeSystemName = StaticCcdaData["MaritalStatusCodeSystemName"];
                p.maritalStatusCode.displayName = patientData["MaritialStatus"];
            }
            if (lstRaceCodes != null && lstRaceCodes.Count > 0)
            {
                p.raceCode1 = new List<CE>();
                var firstRace = lstRaceCodes[0];
                if (!string.IsNullOrWhiteSpace(firstRace["RaceCode"]) && firstRace["RaceCode"] != "UNK")
                {
                    p.raceCode = new CE
                    {
                        codeSystem = StaticCcdaData["RaceCode"],
                        codeSystemName = "OMB Standards for Race and Ethnicity",
                        code = firstRace["RaceCode"],
                        displayName = firstRace["RaceName"],
                    };
                }
                else
                {
                    p.raceCode = new CE
                    {
                        nullFlavor = "UNK",
                        displayName = "Unknown",
                    };
                }
                lstRaceCodes = lstRaceCodes.Where(a => a.Keys != firstRace.Keys).ToList();
                foreach (Dictionary<string, string> itemr in lstRaceCodes)
                {
                    if (!string.IsNullOrWhiteSpace(itemr["RaceCode"]))
                    {
                        p.raceCode1.Add(
                            new CE
                            {
                                code = itemr["RaceCode"],
                                codeSystem = StaticCcdaData["RaceCode"],
                                codeSystemName = "OMB Standards for Race and Ethnicity",
                                displayName = itemr["RaceName"],
                            });
                    }
                }
            }
            else
            {
                p.raceCode = new CE
                {
                    nullFlavor = "UNK",
                    displayName = "Unknown",
                };
            }
            if (lstEthnicityCodes != null && lstEthnicityCodes.Count > 0)
            {
                var firstItem = lstEthnicityCodes[0];
                if (!string.IsNullOrWhiteSpace(firstItem["EthnicityCode"]) && firstItem["EthnicityCode"] != "UNK")
                {
                    p.ethnicGroupCode = new CE
                    {
                        codeSystem = StaticCcdaData["RaceCode"],
                        codeSystemName = "OMB Standards for Race and Ethnicity",
                        code = firstItem["EthnicityCode"],
                        displayName = firstItem["EthnicityName"],
                    };
                }
                else
                {
                    p.ethnicGroupCode = new CE
                    {
                        nullFlavor = "UNK",
                        displayName = "Unknown",
                    };
                }
                lstEthnicityCodes = lstEthnicityCodes.Where(a => a.Keys != firstItem.Keys).ToList();
                p.ethnicGroupCode1 = new List<DE>();
                foreach (Dictionary<string, string> itemr in lstEthnicityCodes)
                {
                    p.ethnicGroupCode1.Add(
                        new DE
                        {
                            codeSystem = StaticCcdaData["RaceCode"],
                            codeSystemName = "OMB Standards for Race and Ethnicity",
                            code = itemr["EthnicityCode"],
                            displayName = itemr["EthnicityName"]
                        });
                }
            }
            else
            {
                p.ethnicGroupCode = new CE
                {
                    nullFlavor = "UNK",
                    displayName = "Unknown",
                };
            }

            string languageCode = patientData["PatientLanguageCode"];
            if (!string.IsNullOrWhiteSpace(languageCode))
            {
                if (languageCode == "eng")
                    languageCode = "en-US";
                p.languageCommunication = new List<LanguageCommunication>()
                {
                    new LanguageCommunication
                    {
                        languageCode = new CS{ code = languageCode },
                        preferenceInd = new BL { value = true , valueSpecified = true}
                    }
                };
            }
            else
            {
                p.languageCommunication = new List<LanguageCommunication>()
                {
                    new LanguageCommunication
                    {
                        nullFlavor="NA"
                    }
                };
            }
            if (DocumentTemplate == DocumentTemplateType.CancerReport)
                p.birthplace = new Birthplace
                {
                    place = new Place
                    {
                        addr = new AD
                        {
                            //use = new List<string>() { }
                            Items = new List<ADXP>
                            {
                                new adxpstate { nullFlavor = "UNK" },
                                new adxpcountry { Text = new List<string> { "US" } }
                            }
                        }
                    }
                };
            pr.patient = p;
        }

