        private static void MakeCcdaBody(ClinicalDocument ccda, CCDADataModel objCcdaModel)
        {
            StructuredBody sb = new StructuredBody { component = new List<Component3>() };
            if (objCcdaModel != null && DocumentTemplate == DocumentTemplateType.AUPReport)
            {
                AddAUPComponent(sb, objCcdaModel);
            }
            else if (objCcdaModel != null && DocumentTemplate == DocumentTemplateType.AROReport)
            {
                AddAROComponent(sb, objCcdaModel);
            }
            else if (objCcdaModel != null && objCcdaModel.Components != null)
            {
                if (!string.IsNullOrWhiteSpace(objCcdaModel.IsConfidential) && objCcdaModel.IsConfidential.ToLower() == "true")
                    AddClinicalPrivacy(sb, objCcdaModel);
                if (DocumentTemplate == DocumentTemplateType.HealthCareSurveys)
                    AddPatientInfoComponent(sb, objCcdaModel);
                if (DocumentTemplate != DocumentTemplateType.CancerReport)
                {
                    foreach (Component objComponent in objCcdaModel.Components)
                    {
                        if ((objComponent.componentName.ToLower().IndexOf("smokingstatus") > -1 || objComponent.componentName.ToLower().IndexOf("socialh") > -1) && (DocumentTemplate == DocumentTemplateType.ClinicalSummary || DocumentTemplate == DocumentTemplateType.DataPortability || DocumentTemplate == DocumentTemplateType.ReferralSummary || DocumentTemplate == DocumentTemplateType.ReferralNote || DocumentTemplate == DocumentTemplateType.ContinutyofCaredocument || DocumentTemplate == DocumentTemplateType.CCDAServiceComponent
                            || DocumentTemplate == DocumentTemplateType.CCDVDT || DocumentTemplate == DocumentTemplateType.ReferralNoteVDT))
                            AddSocialHistoryComponent(sb, objCcdaModel);

                        else if (objComponent.componentName.ToLower().IndexOf("problem") > -1 && (DocumentTemplate == DocumentTemplateType.ClinicalSummary || DocumentTemplate == DocumentTemplateType.DataPortability || DocumentTemplate == DocumentTemplateType.ReferralSummary || DocumentTemplate == DocumentTemplateType.ReferralNote || DocumentTemplate == DocumentTemplateType.ContinutyofCaredocument || DocumentTemplate == DocumentTemplateType.CCDAServiceComponent || DocumentTemplate == DocumentTemplateType.CCDVDT || DocumentTemplate == DocumentTemplateType.ReferralNoteVDT))
                            AddProblemListComponent(sb, objCcdaModel);

                        else if (objComponent.componentName.ToLower().IndexOf("allerg") > -1 && (DocumentTemplate == DocumentTemplateType.ClinicalSummary || DocumentTemplate == DocumentTemplateType.DataPortability || DocumentTemplate == DocumentTemplateType.ReferralSummary || DocumentTemplate == DocumentTemplateType.ReferralNote || DocumentTemplate == DocumentTemplateType.ContinutyofCaredocument || DocumentTemplate == DocumentTemplateType.CCDAServiceComponent || DocumentTemplate == DocumentTemplateType.CCDVDT || DocumentTemplate == DocumentTemplateType.ReferralNoteVDT))
                            AddAllergiesComponent(sb, objCcdaModel);

                        else if (objComponent.componentName.ToLower().IndexOf("medication") > -1 && (DocumentTemplate == DocumentTemplateType.ClinicalSummary || DocumentTemplate == DocumentTemplateType.DataPortability || DocumentTemplate == DocumentTemplateType.ReferralSummary || DocumentTemplate == DocumentTemplateType.ReferralNote || DocumentTemplate == DocumentTemplateType.ContinutyofCaredocument || DocumentTemplate == DocumentTemplateType.CCDAServiceComponent || DocumentTemplate == DocumentTemplateType.CCDVDT || DocumentTemplate == DocumentTemplateType.ReferralNoteVDT))
                            AddMedicationComponent(sb, objCcdaModel);

                        else if (objComponent.componentName.ToLower().IndexOf("immunization") > -1 && (DocumentTemplate == DocumentTemplateType.ClinicalSummary || DocumentTemplate == DocumentTemplateType.DataPortability || DocumentTemplate == DocumentTemplateType.ReferralSummary || DocumentTemplate == DocumentTemplateType.ReferralNote || DocumentTemplate == DocumentTemplateType.ContinutyofCaredocument || DocumentTemplate == DocumentTemplateType.CCDAServiceComponent || DocumentTemplate == DocumentTemplateType.CCDVDT || DocumentTemplate == DocumentTemplateType.ReferralNoteVDT))
                            AddImmunizationComponent(sb, objCcdaModel);

