                {
                    Items = new List<object>
                    {
                        new StrucDocTh
                        {
                            Text = new List<string> {"Body Temperature"},
                            align = StrucDocThAlign.left,
                            alignSpecified = true
                        }
                    }
                };
                tbody.tr.Add(bodyTr);
                bodyTr = new StrucDocTr
                {
                    Items = new List<object>
                    {
