                        {
                            new StrucDocContent
                            {
                                ID = string.Concat("vit", ++id),
                                Text = new List<string> { RespiratoryRate }
                            }
                        };
                    }
                }
                vitalSignsComponent.section.entry = new List<Entry>();
                id = 0;
                foreach (var dr in lstVitalSigns)
