                    // birthSexObservation.id = new List<II> { new II { root = StaticCcdaData["UniqueIdentifierID"] } };

                    birthSexObservation.code = new CD
                    {
                        code = "76689-9",
                        codeSystem = "2.16.840.1.113883.6.1",
