        private static void AddCancerComponent(StructuredBody sb, CCDADataModel objCcdaModel)
        {
            var instructionsComponent = HelperMethods.IntializeComponent3(new List<string> { "2.16.840.1.113883.10.13.2" }, "72135-7", "2.16.840.1.113883.6.1", "LOINC", "Cancer diagnosis", "CANCER DIAGNOSIS");
            instructionsComponent.section.templateId[0].extension = "2015-02-05";
            StrucDocTable table = new StrucDocTable
            {
                width = "100%",
                border = "1",
                Items = new List<object>()
            };
            RootIdCancerDisease = Guid.NewGuid().ToString();
            instructionsComponent.section.text.Items.Add(table);
            List<Entry> entryList = new List<Entry>();
            instructionsComponent.section.entry = entryList;
            var lstCancerDiseases = objCcdaModel.lstProblemsCancer;
            if (lstCancerDiseases != null && lstCancerDiseases.Count > 0)
            {
                #region TableHeader

                table.thead = new StrucDocThead
                {
                    tr = new List<StrucDocTr>
                    {
                        new StrucDocTr
                        {
                            Items = new List<object>
                            {
                                new StrucDocTh{ Text = new List<string>{ "Diagnosis Date" } },
                                new StrucDocTh{ Text = new List<string>{ "Primary Site" } },
                                new StrucDocTh{ Text = new List<string>{ "Laterality" } },
                                new StrucDocTh{ Text = new List<string>{ "Histology" } },
                                new StrucDocTh{ Text = new List<string>{ "Behavior" } },
                                new StrucDocTh{ Text = new List<string>{ "Diagnostic Confirmation" } },
                                new StrucDocTh{ Text = new List<string>{ "Grade" } },
                                new StrucDocTh{ Text = new List<string>{ "Stage" } },
                            }
                        }
                    }
                };

                #endregion



                table.tbody = new List<StrucDocTbody>();
                StrucDocTbody tBody = new StrucDocTbody();
                table.tbody.Add(tBody);
                tBody.tr = new List<StrucDocTr>();
                var i = 0;
                foreach (Dictionary<string, string> dr in lstCancerDiseases)
                {
                    #region TableBody
                    i++;

                    var tr = new StrucDocTr { Items = new List<object>() };
                    //var name = MDVUtility.ToStr(dr["Name"]);
                    var diagnosisDate = MDVUtility.ToStr(dr["DiagnosisDate"]);
                    if (!string.IsNullOrWhiteSpace(diagnosisDate))
                    {
                        tr.Items.Add(new StrucDocTd { Text = new List<string> { Convert.ToDateTime(diagnosisDate).ToString("MM/dd/yyyy") } });
                    }
                    var PrimarySite = MDVUtility.ToStr(dr["PrimarySite"]);
                    if (!string.IsNullOrWhiteSpace(PrimarySite))
                    {
                        tr.Items.Add(new StrucDocTd
                        {
                            ID = string.Concat("PrimarySite_", i),
                            Text = new List<string> { PrimarySite }
                        });
                    }
                    var Laterality = MDVUtility.ToStr(dr["Laterality"]);
                    if (!string.IsNullOrWhiteSpace(Laterality))
                    {
                        tr.Items.Add(new StrucDocTd
                        {
                            ID = string.Concat("Laterality_", i),
                            Text = new List<string> { Laterality == "None" ? "" : Laterality }
                        });
                    }
                    var Histology = MDVUtility.ToStr(dr["Histology"]);
                    if (!string.IsNullOrWhiteSpace(Histology))
                    {
                        tr.Items.Add(new StrucDocTd
                        {
                            ID = string.Concat("Histology_", i),
                            Text = new List<string> { Histology == "None" ? "" : Histology }
                        });
                    }
                    var Behavior = MDVUtility.ToStr(dr["Behavior"]);
                    if (!string.IsNullOrWhiteSpace(Behavior))
                    {
                        tr.Items.Add(new StrucDocTd
                        {
                            ID = string.Concat("Behavior_", i),
                            Text = new List<string> { Behavior == "None" ? "" : Behavior }
                        });
                    }
                    var DiagnosticConfirmation = MDVUtility.ToStr(dr["DiagnosticConfirmation"]);
                    if (!string.IsNullOrWhiteSpace(DiagnosticConfirmation))
                    {
                        tr.Items.Add(new StrucDocTd
                        {
                            ID = string.Concat("Confirmation_", i),
                            Text = new List<string> { DiagnosticConfirmation == "None" ? "" : DiagnosticConfirmation }
                        });
                    }
                    var Grade = MDVUtility.ToStr(dr["Grade"]);
                    if (!string.IsNullOrWhiteSpace(Grade))
                    {
                        tr.Items.Add(new StrucDocTd
                        {
                            ID = string.Concat("Grade_", i),
                            Text = new List<string> { Grade == "None" ? "" : Grade }
                        });
                    }
                    var Stage = MDVUtility.ToStr(dr["ClinicalStageGroup"]);
                    if (!string.IsNullOrWhiteSpace(Stage))
                    {
                        tr.Items.Add(new StrucDocTd
                        {
                            ID = string.Concat("StageGroup_", i),
                            Text = new List<string> { Stage == "None" ? "" : Stage }
                        });
                    }
                    tBody.tr.Add(tr);
                    //}

                    var EffectiveDate = MDVUtility.ToStr(dr["EffectiveDate"]);
                    var dtStartDate1 = DateTime.Now;
                    if (!string.IsNullOrWhiteSpace(EffectiveDate))
                        dtStartDate1 = Convert.ToDateTime(EffectiveDate);
                    string lowTime1 = HelperMethods.SetDateTime(dtStartDate1);

