        private static void AddFamilyHistoryComponent(StructuredBody sb, CCDADataModel objCcdaModel)
        {
            List<LisValues> FmailyMemberList = new List<LisValues>();
            var familyHistoryComponent = HelperMethods.IntializeComponent3(
            new List<string> { "2.16.840.1.113883.10.20.22.2.15", },
            "10157-6", "2.16.840.1.113883.6.1", "LOINC", "Family History", "FAMILY HISTORY");
            familyHistoryComponent.section.templateId[0].extension = "2014-06-09";
            var text = familyHistoryComponent.section.text;
            familyHistoryComponent.section.entry = new List<Entry>();
            var lstFamilyHx = objCcdaModel.lstFamilyHx;
            if (lstFamilyHx != null && lstFamilyHx.Count > 0)
            {
                #region Table Structure

                var table = new StrucDocTable();
                text.Items.Add(table);
                table.border = "1";
                table.width = "100%";
                table.thead = new StrucDocThead { tr = new List<StrucDocTr>() };
                var headerTr = new StrucDocTr();
                table.thead.tr.Add(headerTr);
                headerTr.Items = new List<object>
                {
                    new StrucDocTh {Text = new List<string> {"Relationship"}},
                    new StrucDocTh {Text = new List<string> {"Diagnosis"}},
                    new StrucDocTh {Text = new List<string> {"Age At Onset"}}
                };
                table.tbody = new List<StrucDocTbody>();
                var tbody = new StrucDocTbody();
                table.tbody.Add(tbody);
                tbody.tr = new List<StrucDocTr>();
                foreach (var dr in lstFamilyHx)
                {
                    string strDescription = string.Empty;
                    string AgeDiagnosis = string.Empty;
                    if (!string.IsNullOrWhiteSpace(dr["IsRelativeDied"]) && Convert.ToBoolean(dr["IsRelativeDied"]))
                    {
                        strDescription = dr["SNOMEDDescription"] + " (cause of death)";
                    }
                    else
                    {
                        strDescription = dr["SNOMEDDescription"];
                    }
                    if (!string.IsNullOrWhiteSpace(dr["AgeAtDiagnosis"]))
                    {
                        AgeDiagnosis = dr["AgeAtDiagnosis"];
                    }
                    else
                    {
                        AgeDiagnosis = dr["AgeAtDeath"];
                    }
                    string Relationship = string.Empty;
                    if (!string.IsNullOrWhiteSpace(dr["HealthStatus"]))
                    {
                        Relationship = dr["Relationship"] + " (" + dr["HealthStatus"] + ")";
                    }
                    else
                    {
                        Relationship = dr["Relationship"];
                    }
                    var bodyTr = new StrucDocTr
                    {
                        Items = new List<object>
                        {
                            new StrucDocTd
                            {
                                Text = new List<string>
                                {
                                    Relationship
                                }
                            }
                        }
                    };
                    bodyTr.Items.Add(new StrucDocTd { Text = new List<string> { strDescription } });
                    bodyTr.Items.Add(new StrucDocTd { Text = new List<string> { AgeDiagnosis } });
                    tbody.tr.Add(bodyTr);
                }
                #endregion Table Structure

                #region XML Structure
                foreach (var dr in lstFamilyHx)
                {
                    string Familymember = dr["Relationship"].ToString();
                    if (!string.IsNullOrWhiteSpace(Familymember) && FmailyMemberList.Where(m => m.Description == Familymember).Count() == 0)
                    {
                        FmailyMemberList.Add(new LisValues { Description = Familymember });
                        var familyHistoryEntry = new Entry();
                        familyHistoryEntry.typeCode = x_ActRelationshipEntry.DRIV;
                        familyHistoryComponent.section.entry.Add(familyHistoryEntry);
                        var familyHistoryOrganizer = new Organizer();
                        familyHistoryOrganizer.classCode = x_ActClassDocumentEntryOrganizer.CLUSTER;
                        familyHistoryOrganizer.moodCode = "EVN";
                        familyHistoryEntry.Item = familyHistoryOrganizer;
                        familyHistoryOrganizer.templateId = new List<II>()
                        {
                            new II { root = "2.16.840.1.113883.10.20.22.4.45" , extension = "2014-06-09"}
                        };
                        familyHistoryOrganizer.id = new List<II> { new II { root = Guid.NewGuid().ToString() } };
                        familyHistoryOrganizer.statusCode = new CS
                        {
                            code = "completed"
                        };

                        #region Subject

                        var subject = new Subject();
                        familyHistoryOrganizer.subject = subject;

                        var relatedSubject = new RelatedSubject();
                        subject.relatedSubject = relatedSubject;
                        relatedSubject.classCode = "PRS";
                        relatedSubject.code = new CE
                        {
                            code = dr["RelationshipCode"],
                            codeSystem = "2.16.840.1.113883.5.111",
                            codeSystemName = "FamilyRelationshipRoleType",
                            displayName = dr["Relationship"],
                            translation = new List<CD>
                            {
                                string.IsNullOrWhiteSpace(dr["RelationshipSNOMEDId"]) == true ? new CD {nullFlavor = "NI" }:
                                new CD
                                {
                                    code = dr["RelationshipSNOMEDId"],
                                    codeSystem = "2.16.840.1.113883.6.96",
                                    codeSystemName = "SNOMED",
                                    displayName = dr["RelationshipSNOMEDDescription"],
                                }
                            }
                        };
                        string gender = HelperMethods.GetGenderFromRelationship(dr["Relationship"]);
                        string genderCode = string.Empty;
                        if (gender == "Male")
                        {
                            genderCode = "M";
                        }
                        else if (gender == "Female")
                        {
                            genderCode = "F";
                        }
                        else if (gender == "Unknown")
                        {
                            genderCode = "UNK";
                        }
                        relatedSubject.subject = new SubjectPerson
                        {
                            id = new List<II>
                            {
                                new II { root = "2.16.840.1.113883.19.5.99999.2", extension = "99999999" }
                            },
                            administrativeGenderCode = string.IsNullOrWhiteSpace(genderCode) == true ? new CE { nullFlavor = "NI" } :
                            new CE
                            {
                                code = genderCode,
                                codeSystem = StaticCcdaData["GenderCodeCodeSystem"],
                                codeSystemName = StaticCcdaData["GenderCodeCodeSystemName"],
                                displayName = gender
                            },
                            birthTime = string.IsNullOrWhiteSpace(dr["BirthYear"]) == true ? new TS { nullFlavor = "NI" } :
                            new TS
                            {
                                value = dr["BirthYear"].ToString()
                            }
                        };
                        #endregion Subject

                        var familyHistoryOrganizerComponent = new List<Component4>();
                        foreach (var drInner in lstFamilyHx)
                        {
                            if (Familymember == drInner["Relationship"].ToString())
                            {
                                var OrganizerComponent = new Component4();
                                familyHistoryOrganizerComponent.Add(OrganizerComponent);
                                familyHistoryOrganizer.component = familyHistoryOrganizerComponent;

                                var familyHistoryObservation = new Observation();
                                OrganizerComponent.Item = familyHistoryObservation;

                                familyHistoryObservation.classCode = "OBS";
                                familyHistoryObservation.moodCode = x_ActMoodDocumentObservation.EVN;
                                familyHistoryObservation.templateId = new List<II>
                                {
                                    new II { root = "2.16.840.1.113883.10.20.22.4.46",extension="2014-06-09" },
                                };
                                familyHistoryObservation.id = new List<II> { new II { root = Guid.NewGuid().ToString() } };
                                familyHistoryObservation.code = new CD
                                {
                                    code = "75323-6",
                                    displayName = "Condition",
                                    codeSystemName = "LOINC",
                                    codeSystem = "2.16.840.1.113883.6.1"
                                };
                                familyHistoryObservation.statusCode = new CS
                                {
                                    code = "completed"
                                };
                                familyHistoryObservation.effectiveTime = string.IsNullOrWhiteSpace(drInner["BirthYear"]) == true ? new IVL_TS { nullFlavor = "NI" } : new IVL_TS { value = drInner["BirthYear"].ToString() };
                                familyHistoryObservation.value = new List<ANY>
                                {
                                    string.IsNullOrWhiteSpace(drInner["SNOMEDID"]) == true ? new CD { nullFlavor = "NI" } :
                                    new CD
                                    {
                                        code = drInner["SNOMEDID"],
                                        codeSystem = "2.16.840.1.113883.6.96",
                                        codeSystemName = "SNOMED-CT",
                                        displayName = drInner["SNOMEDDescription"],
                                        valueSet = "2.16.840.1.113883.3.88.12.3221.7.4"
                                    }
                                };
                                var entryRelationshipFamilyHistory = new List<EntryRelationship>();
                                familyHistoryObservation.entryRelationship = entryRelationshipFamilyHistory;
                                string Age = string.Empty;
                                if (!string.IsNullOrWhiteSpace(drInner["IsRelativeDied"]) && Convert.ToBoolean(drInner["IsRelativeDied"]))
                                {
                                    if (!string.IsNullOrWhiteSpace(drInner["AgeAtDiagnosis"]))
                                    {
                                        Age = drInner["AgeAtDiagnosis"];
                                    }
                                    else
                                    {
                                        Age = drInner["AgeAtDeath"];
                                    }
                                    var entryRelationshipFamilyHistory1 = new EntryRelationship
                                    {
                                        typeCode = x_ActRelationshipEntryRelationship.CAUS,
                                        Item = new Observation()
                                        {
                                            classCode = "OBS",
                                            moodCode = x_ActMoodDocumentObservation.EVN,
                                            templateId = new List<II>
                                            {
                                                new II {root="2.16.840.1.113883.10.20.22.4.47" }
                                            },
                                            id = new List<II> { new II { root = Guid.NewGuid().ToString() } },
                                            code = new CD
                                            {
                                                code = "ASSERTION",
                                                codeSystem = "2.16.840.1.113883.5.4"
                                            },
                                            statusCode = new CS
                                            {
                                                code = "completed"
                                            },
                                            value = new List<ANY>
                                            {
                                                new CD
                                                {
                                                    code = "419099009",
                                                    displayName = "Dead",
                                                    codeSystem = "2.16.840.1.113883.6.96",
                                                    codeSystemName = "SNOMED-CT",
                                                }
                                            }

                                        }
                                    };
                                    entryRelationshipFamilyHistory.Add(entryRelationshipFamilyHistory1);
                                }
                                else
                                {
                                    Age = drInner["AgeAtDiagnosis"];
                                }

                                var entryRelationshipFamilyHistory2 = new EntryRelationship
                                {
                                    typeCode = x_ActRelationshipEntryRelationship.SUBJ,
                                    inversionInd = true,
                                    inversionIndSpecified = true,
                                    Item = new Observation()
                                    {
                                        classCode = "OBS",
                                        moodCode = x_ActMoodDocumentObservation.EVN,
                                        templateId = new List<II>
                                        {
                                            new II {root="2.16.840.1.113883.10.20.22.4.31" }
                                        },
                                        id = new List<II> { new II { root = Guid.NewGuid().ToString() } },
                                        code = new CD
                                        {
                                            code = "445518008",
                                            displayName = "Age At Onset",
                                            codeSystem = "2.16.840.1.113883.6.96",
                                            codeSystemName = "SNOMED CT"
                                        },
                                        statusCode = new CS
                                        {
                                            code = "completed"
                                        },
                                        value = new List<ANY>
                                        {
                                            string.IsNullOrWhiteSpace(Age) == true ? new PQ {nullFlavor="NI" }:
                                            new PQ
                                            {
                                                value =  Age,
                                                unit = "a"
                                            }
                                        }
                                    }
                                };
                                entryRelationshipFamilyHistory.Add(entryRelationshipFamilyHistory2);
                            }
                        }
                    }
                }
                #endregion XML Structure
            }
            else
            {
                var content = new StrucDocContent();
                text.Items.Add(content);
                content.Text = new List<string> { "Not included in document" };
                var familyHistoryEntry = new Entry();
                familyHistoryEntry.typeCode = x_ActRelationshipEntry.DRIV;
                familyHistoryComponent.section.entry.Add(familyHistoryEntry);
                var familyHistoryOrganizer = new Organizer();
                familyHistoryOrganizer.classCode = x_ActClassDocumentEntryOrganizer.CLUSTER;
                familyHistoryOrganizer.moodCode = "EVN";
                familyHistoryEntry.Item = familyHistoryOrganizer;
                familyHistoryOrganizer.templateId = new List<II>()
                {
                    new II { root = "2.16.840.1.113883.10.20.22.4.45" }
                };
                familyHistoryOrganizer.id = new List<II> { new II { root = Guid.NewGuid().ToString() } };
                familyHistoryOrganizer.statusCode = new CS
                {
                    code = "completed"
                };
                var subject = new Subject();
                familyHistoryOrganizer.subject = subject;

                var relatedSubject = new RelatedSubject();
                subject.relatedSubject = relatedSubject;
                relatedSubject.classCode = "PRS";
                relatedSubject.code = new CE
                {
                    nullFlavor = "NI",
                    translation = new List<CD>
                    {
                        new CD {nullFlavor = "NI" }
                    }
                };
                relatedSubject.subject = new SubjectPerson
                {
                    id = new List<II>
                    {
                        new II { root = "2.16.840.1.113883.19.5.99999.2", extension = "99999999" }
                    },
                    administrativeGenderCode = new CE { nullFlavor = "NI" },
                    birthTime = new TS { nullFlavor = "NI" }
                };
                var familyHistoryOrganizerComponent = new List<Component4>();
                var OrganizerComponent = new Component4();
                familyHistoryOrganizerComponent.Add(OrganizerComponent);
                familyHistoryOrganizer.component = familyHistoryOrganizerComponent;

                var familyHistoryObservation = new Observation();
                OrganizerComponent.Item = familyHistoryObservation;

                familyHistoryObservation.classCode = "OBS";
                familyHistoryObservation.moodCode = x_ActMoodDocumentObservation.EVN;
                familyHistoryObservation.templateId = new List<II>
                {
                    new II { root = "2.16.840.1.113883.10.20.22.4.46" },
                };
                familyHistoryObservation.id = new List<II> { new II { root = Guid.NewGuid().ToString() } };
                familyHistoryObservation.code = new CD
                {
                    code = "75323-6",
                    displayName = "Condition",
                    codeSystemName = "LOINC",
                    codeSystem = "2.16.840.1.113883.6.1"
                };
                familyHistoryObservation.statusCode = new CS
                {
                    nullFlavor = "NI"
                };
                familyHistoryObservation.effectiveTime = new IVL_TS { nullFlavor = "NI" };
                familyHistoryObservation.value = new List<ANY>
                {
                    new CD { nullFlavor = "NI" }
                };
                var entryRelationshipFamilyHistory = new List<EntryRelationship>();
                familyHistoryObservation.entryRelationship = entryRelationshipFamilyHistory;
                var entryRelationshipFamilyHistory2 = new EntryRelationship
                {
                    typeCode = x_ActRelationshipEntryRelationship.SUBJ,
                    inversionInd = true,
                    inversionIndSpecified = true,
                    Item = new Observation()
                    {
                        classCode = "OBS",
                        moodCode = x_ActMoodDocumentObservation.EVN,
                        templateId = new List<II>
                        {
                            new II {root="2.16.840.1.113883.10.20.22.4.31" }
                        },
                        id = new List<II> { new II { root = Guid.NewGuid().ToString() } },
                        code = new CD
                        {
                            code = "445518008",
                            displayName = "Age At Onset",
                            codeSystem = "2.16.840.1.113883.6.96",
