        private static void AddHealthConcernsSectionComponent(StructuredBody sb, CCDADataModel objCcdaModel)
        {
            Component3 instructionsComponent = HelperMethods.IntializeComponent3(new List<string> { "2.16.840.1.113883.10.20.22.2.58" }, "75310-3", "2.16.840.1.113883.6.1", "LOINC", "Health Concerns Document", "HEALTH CONCERNS SECTION");

            instructionsComponent.section.templateId[0].extension = "2015-08-01";
            var text = instructionsComponent.section.text;

            #region Concerns Table
            var lstConcerns = objCcdaModel.lstHealthConsern;
            if (lstConcerns != null && lstConcerns.Count > 0)
            {
                StrucDocTable table = new StrucDocTable
                {
                    width = "100%",
                    border = "1",
                    Items = new List<object>()
                };

                instructionsComponent.section.text.Items.Add(table);
                #region TableHeader

                table.thead = new StrucDocThead
                {
                    tr = new List<StrucDocTr>
                    {
                        new StrucDocTr
                        {
                            Items = new List<object>
                            {
                                new StrucDocTh{ Text = new List<string>{ "Concern" } },
                                new StrucDocTh{ Text = new List<string>{ "Status" } },
                                new StrucDocTh{ Text = new List<string>{ "Date" } },
                            }
                        }
                    }
                };

                #endregion

                #region TableBody

                table.tbody = new List<StrucDocTbody>();
                var tBody = new StrucDocTbody();
                table.tbody.Add(tBody);
                tBody.tr = new List<StrucDocTr>();
                var i = 0;
                foreach (var dr in lstConcerns)
                {
                    i++;
                    var tr = new StrucDocTr { Items = new List<object>() };
                    var name = MDVUtility.ToStr(dr["Name"]);
                    var snomedid = MDVUtility.ToStr(dr["SNOMEDID"]);

                    if (!string.IsNullOrWhiteSpace(name))
                    {
                        //name = name + ", [SNOMED-CT: " + snomedid + "]";
                        tr.Items.Add(new StrucDocTd { ID = "concern_" + i, Text = new List<string> { name } });
                    }

                    tr.Items.Add(new StrucDocTd { Text = new List<string> { dr["Status"] } });
                    var date = dr["Date"];
                    if (!string.IsNullOrWhiteSpace(date))
                        date = Convert.ToDateTime(date).ToString("MM/dd/yyyy");
                    tr.Items.Add(new StrucDocTd { Text = new List<string> { date } });
                    tBody.tr.Add(tr);
                }

                #endregion
            }

            #endregion Concerns Table

            #region Observation Table
            var lstObservation = objCcdaModel.lstHealthObservation;
            if (lstObservation != null && lstObservation.Count > 0)
            {
                StrucDocTable table = new StrucDocTable
                {
                    width = "100%",
                    border = "1",
                    Items = new List<object>()
                };

                instructionsComponent.section.text.Items.Add(table);
                #region TableHeader

                table.thead = new StrucDocThead
                {
                    tr = new List<StrucDocTr>
                    {
                        new StrucDocTr
                        {
                            Items = new List<object>
                            {
                                new StrucDocTh{ Text = new List<string>{ "Observations" } },
                                new StrucDocTh{ Text = new List<string>{ "Status" } },
                                new StrucDocTh{ Text = new List<string>{ "Date" } },
                            }
                        }
                    }
                };

                #endregion

                #region TableBody

                table.tbody = new List<StrucDocTbody>();
                var tBody = new StrucDocTbody();
                table.tbody.Add(tBody);
                tBody.tr = new List<StrucDocTr>();
                var i = 0;
                foreach (var dr in lstObservation)
                {
                    i++;
                    var tr = new StrucDocTr { Items = new List<object>() };
                    var name = MDVUtility.ToStr(dr["Name"]);
                    var snomedid = MDVUtility.ToStr(dr["SNOMEDID"]);

                    if (!string.IsNullOrWhiteSpace(name))
                    {
                        tr.Items.Add(new StrucDocTd { ID = "observation" + i, Text = new List<string> { name } });
                    }
                    tr.Items.Add(new StrucDocTd { Text = new List<string> { "Active" } });
                    var date = dr["Date"];
                    if (!string.IsNullOrWhiteSpace(date))
                        date = Convert.ToDateTime(date).ToString("MM/dd/yyyy");
                    tr.Items.Add(new StrucDocTd { Text = new List<string> { date } });
                    tBody.tr.Add(tr);
                }

                #endregion
            }
            #endregion Observation Table

            #region Observation Table
            var lstRisks = objCcdaModel.lstHealthRisks;
            if (lstRisks != null && lstRisks.Count > 0)
            {
                StrucDocTable table = new StrucDocTable
                {
                    width = "100%",
                    border = "1",
                    Items = new List<object>()
                };

                instructionsComponent.section.text.Items.Add(table);
                #region TableHeader

                table.thead = new StrucDocThead
                {
                    tr = new List<StrucDocTr>
                    {
                        new StrucDocTr
                        {
                            Items = new List<object>
                            {
                                new StrucDocTh{ Text = new List<string>{ "Risk" } },
                                new StrucDocTh{ Text = new List<string>{ "Status" } },
                                new StrucDocTh{ Text = new List<string>{ "Date" } },
                            }
                        }
                    }
                };

                #endregion

                #region TableBody

                table.tbody = new List<StrucDocTbody>();
                var tBody = new StrucDocTbody();
                table.tbody.Add(tBody);
                tBody.tr = new List<StrucDocTr>();
                var i = 0;
                foreach (var dr in lstRisks)
                {
                    i++;
                    var tr = new StrucDocTr { Items = new List<object>() };
                    var name = MDVUtility.ToStr(dr["Name"]);
                    var snomedid = MDVUtility.ToStr(dr["SNOMEDID"]);

                    if (!string.IsNullOrWhiteSpace(name))
                    {
