                                            ? "-"
                                            : Convert.ToDateTime(dr["VisitDate"]).ToString("MM/dd/yyyy")
                                    }
                                },
                            }
                    };
                    tbody.tr.Add(bodyTr);
                }
                #endregion Encounter
                component.section.entry = new List<Entry>();
