            {
                var filter = new Dictionary<string, string> { { "Status", "Planned" }, };
                lstCompletedInterv = lstInterventions.Where(a => a.Keys != filter.Keys).ToList();
                lstPlannedInterv = lstInterventions.Where(a => a.Keys == filter.Keys).ToList();
            }
            var i = 0;
            #region Planned Intervantions Table
            if (lstPlannedInterv != null && lstPlannedInterv.Count > 0)
            {

                StrucDocTable table1 = new StrucDocTable
                {
                    width = "100%",
                    border = "1",
                    Items = new List<object>()
                };

                component.section.text.Items.Add(table1);
                #region TableHeader

