        private static void AddOutcomesComponent(StructuredBody sb, CCDADataModel objCcdaModel)
        {
            Component3 component = HelperMethods.IntializeComponent3(new List<string> { "2.16.840.1.113883.10.20.22.2.61" }, "11383-7", "2.16.840.1.113883.6.1", "LOINC", "Patient Problem Outcome", "HEALTH STATUS EVALUATIONS/OUTCOMES SECTION");

            //instructionsComponent.section.templateId[0].extension = "2015-08-01";
            var text = component.section.text;
            var lstOutComes = objCcdaModel.lstOutComes;
            var lstOutComesGoals = objCcdaModel.lstInsurance ?? new List<Dictionary<string, string>>();
            var lstOutComesInterVen = objCcdaModel.lstInsurance ?? new List<Dictionary<string, string>>();
            StrucDocTable table = new StrucDocTable();

            #region OutComes Table
            if (lstOutComesGoals.Count > 0 || lstOutComesInterVen.Count > 0)
            {
                table = new StrucDocTable
                {
                    width = "100%",
                    border = "1",
                    Items = new List<object>()
                };

                component.section.text.Items.Add(table);
                #region TableHeader

                table.thead = new StrucDocThead
                {
                    tr = new List<StrucDocTr>
                    {
                        new StrucDocTr
                        {
                            Items = new List<object>
                            {
                                new StrucDocTh{ Text = new List<string>{ "Item" } },
                                new StrucDocTh{ Text = new List<string>{ "Outcome" } },
                                new StrucDocTh{ Text = new List<string>{ "Date" } },
                            }
                        }
                    }
                };

                #endregion
            }


            #region TableBody

            table.tbody = new List<StrucDocTbody>();
            var tBody = new StrucDocTbody();
            table.tbody.Add(tBody);
            tBody.tr = new List<StrucDocTr>();
            var i = 0;
            foreach (var dr in lstOutComes)
            {
                i++;
                var tr = new StrucDocTr { Items = new List<object>() };
                var name = MDVUtility.ToStr(dr["SNOMEDDescription"]);

                if (!string.IsNullOrWhiteSpace(name))
                {
                    tr.Items.Add(new StrucDocTd { Text = new List<string> { name } });
                }
                tr.Items.Add(new StrucDocTd { Text = new List<string> { dr["Value"] } });
                var date = dr["Date"];
                if (!string.IsNullOrWhiteSpace(date))
                    date = Convert.ToDateTime(date).ToString("MM/dd/yyyy");
                tr.Items.Add(new StrucDocTd { Text = new List<string> { date } });
                tBody.tr.Add(tr);
            }

            #endregion

            #endregion Observation Table

            #region Concern XML Entry
            var consernRelationShip = new List<EntryRelationship>();
            foreach (var outCome in lstOutComes)
            {
                #region OutcomeInterventions RelationShips

                if (outCome["Interventions"] != null)
                {
                    foreach (var item in outCome["Interventions"].Split(','))
                    {
                        var entryRelationShipInter = new EntryRelationship
                        {
                            typeCode = x_ActRelationshipEntryRelationship.RSON,
                            Item = new Act
                            {
                                classCode = x_ActClassDocumentEntryAct.ACT,
                                moodCode = x_DocumentActMood.EVN,
                                templateId = new List<II>
                        {
                            new II{root = "2.16.840.1.113883.10.20.22.4.122",}
                        },
                                id = new List<II>
                        {
                            new II
                            {
                                root = StaticCcdaData["InterventionsUniqueKey"]
                            }
                        },
                                code = new CD
                                {
                                    nullFlavor = "NP"
                                },
                                statusCode = new CS
                                {
                                    code = "completed"
                                },
                            }
                        };
                        consernRelationShip.Add(entryRelationShipInter);
                    }
                }
                #endregion OutcomeInterventions RelationShips

                #region OutcomeGoals RelationShips
                if (outCome["GoalsStatus"] != null && outCome["Goals"] != null)
                {
                    int index = 0;
                    string[] GoalsStatus;
                    GoalsStatus = outCome["GoalsStatus"].Split(',');
                    foreach (var item in outCome["Goals"].Split(','))
                    {
                        var entryRelationShipInter = new EntryRelationship
                        {
                            typeCode = x_ActRelationshipEntryRelationship.GEVL,
                            Item = new Act
                            {
                                classCode = x_ActClassDocumentEntryAct.ACT,
                                moodCode = x_DocumentActMood.EVN,
                                templateId = new List<II>
                        {
                            new II{root = "2.16.840.1.113883.10.20.22.4.122",}
                        },
                                id = new List<II>
                        {
                            new II
                            {
                                root = StaticCcdaData["GoalsUniqueKey"]
                            }
                        },
                                code = new CD
                                {
                                    nullFlavor = "NP"
                                },
                                statusCode = new CS
                                {
                                    code = "completed"
                                },
                            }
                        };
                        consernRelationShip.Add(entryRelationShipInter);
                        var statusDes = "Goal achieved";
                        var statusCode = "390802008";
                        var status = "completed";
                        if (GoalsStatus != null && GoalsStatus.Count() > 0)
                        {
                            if (GoalsStatus[index] == "2")
                            {
                                statusDes = "Goal partially achieved";
                                statusCode = "706907002";
                                status = "active";
                            }
                            else if (GoalsStatus[index] == "3")
                            {
                                statusDes = "Not achieved";
                                statusCode = "390801001";
                                status = "active";
                            }
                        }
                        index++;
                        //Status
                        var entryRelationShipStatus = new EntryRelationship
                        {
                            typeCode = x_ActRelationshipEntryRelationship.SPRT,
                            inversionInd = true,
                            Item = new Observation
                            {
                                classCode = "OBS",
                                moodCode = x_ActMoodDocumentObservation.EVN,
                                templateId = new List<II>
                            {
                                new II
                                { root = "2.16.840.1.113883.10.20.22.4.144",}
                            },
                                id = new List<II>
                            {
                                new II
                                {
                                    root = Guid.NewGuid().ToString()
                                }
                            },

                                statusCode = new CS
                                {
                                    code = "completed"
                                },
                                value = new List<ANY>
                                {
                                    new CD
                                    {
                                        code = statusCode,
                                        codeSystem = "2.16.840.1.113883.6.96",
                                        codeSystemName = "SNOMED CT",
                                        displayName = statusDes
                                    }
                                },
                            }
                        };
                        consernRelationShip.Add(entryRelationShipInter);
                    }
                }

                #endregion OutcomeGoals RelationShips

                if (consernRelationShip != null && consernRelationShip.Count > 0)
                {
                    var effecTime = new IVL_TS();
                    var date = MDVUtility.ToStr(outCome["Date"]);
                    var dtStartDate = DateTime.Now;
                    if (!string.IsNullOrWhiteSpace(date))
                        dtStartDate = Convert.ToDateTime(date);
                    string lowTime = HelperMethods.SetDateTime(dtStartDate);
                    if (!string.IsNullOrWhiteSpace(lowTime))
                    {
                        effecTime = new IVL_TS
                        {
                            value = lowTime
                        };
                    }
                    component.section.entry = new List<Entry>
                    {
                        new Entry
                        {
                            Item = new Observation()
                            {
                                classCode = "OBS",
                                moodCode =x_ActMoodDocumentObservation.EVN,
                                templateId= new List<II>
                                {
                                    new II
                                    { root = "2.16.840.1.113883.10.20.22.4.144",}
                                },
                                id = new List<II>
                                {
                                    new II
                                    {
                                        root = Guid.NewGuid().ToString()
                                    }
                                },
                                code = new CD
                                {
                                    code = "44616-1",
                                    codeSystem = "2.16.840.1.113883.6.1",
                                    codeSystemName = "LOINC",
                                    displayName = "Pulse oximetry panel"
                                },
                                statusCode = new CS
                                {
                                    code = "completed"
                                },
                                effectiveTime=effecTime,
                                value=new List<ANY>
                                {
                                    new PQ
                                    {
                                        value=outCome["Value"],
                                        unit="%"
                                    }
                                },
                                author=new List<Author>
                                {
                                    new Author
                                    {
                                         time=effecTime,
                                         assignedAuthor=new AssignedAuthor
                                         {
                                             id = new List<II>
                                            {
                                                new II
                                                {
                                                    root = StaticCcdaData["ProviderOrganizationID"]
                                                }
                                            },
                                         }
                                    }
                                },
                                entryRelationship = consernRelationShip,
                            }
                        }
                    };
                }
            }

            if (lstOutComes == null || lstOutComes.Count == 0)
            {
                text.Items.Add(new StrucDocContent
                {
                    ID = "noOutcome",
                    Text = new List<string> { "Not included in document" }
                });
                component.section.entry = new List<Entry>
                    {
                        new Entry
                        {
                            Item = new Observation()
                            {
                                classCode = "OBS",
                                moodCode = x_ActMoodDocumentObservation.EVN,
                                templateId= new List<II>
                                {
                                    new II
                                    {
                                        root = "2.16.840.1.113883.10.20.22.4.144",
                                    }
                                },
                                id = new List<II>
                                {
                                    new II
                                    {
                                        root = Guid.NewGuid().ToString()
                                    }
                                },
                                code = new CD
                                {
                                  nullFlavor="NI"
                                },
                                statusCode = new CS
                                {
                                     nullFlavor="NI"
                                },
                                entryRelationship = new List<EntryRelationship>
                                {
                                    new EntryRelationship
                                   {
                                        typeCode = x_ActRelationshipEntryRelationship.RSON,
                                        Item = new Act
                                        {
                                            classCode = x_ActClassDocumentEntryAct.ACT,
                                            moodCode = x_DocumentActMood.EVN,
                                            templateId = new List<II>
                                            {
                                                new II{root = "2.16.840.1.113883.10.20.22.4.122",}
                                            },
                                                    id = new List<II>
                                            {
                                                new II
                                                {
                                                    root = StaticCcdaData["InterventionsUniqueKey"]
                                                }
                                            },
                                            code = new CD
                                            {
                                                nullFlavor = "NP"
                                            },
                                            statusCode = new CS
                                            {
                                                code = "completed"
                                            },
                                        }
                                    }
                                }
                            }
                        }
                    };
            }

            #endregion Concern XML Entry



            sb.component.Add(component);

        }
        private static void AddPatientInfoComponent(StructuredBody sb, CCDADataModel objCcdaModel)
        {
            if (objCcdaModel.lstPatientData == null || objCcdaModel.lstPatientData.Count <= 0)
            {
                return;
            }
            var socialHistoryComponent = HelperMethods.IntializeComponent3(
            new List<string> { "2.16.840.1.113883.10.20.22.2.17", "2.16.840.1.113883.10.20.34.2.5" },
            "29762-2", "2.16.840.1.113883.6.1", "LOINC", "Social History", "PATIENT INFORMATION");

            socialHistoryComponent.section.templateId[0].extension = "2014-06-09";
            socialHistoryComponent.section.templateId[1].extension = "2016-07-01";
            var text = socialHistoryComponent.section.text;
            socialHistoryComponent.section.entry = new List<Entry>();
            var lstSocials = objCcdaModel.lstSocials;
            var patientData = objCcdaModel.lstPatientData[0];
            if (lstSocials != null && lstSocials.Count > 0)
            {
                var table = new StrucDocTable();
                text.Items.Add(table);
                table.border = "1";
                table.width = "100%";
                table.thead = new StrucDocThead { tr = new List<StrucDocTr>() };
                var headerTr = new StrucDocTr();
                table.thead.tr.Add(headerTr);
                headerTr.Items = new List<object>
                {
                    new StrucDocTh {Text = new List<string> {"Tobacco Use"}},
                };

                table.tbody = new List<StrucDocTbody>();
                var tbody = new StrucDocTbody();
                table.tbody.Add(tbody);

                tbody.tr = new List<StrucDocTr>();

                var bodyTr = new StrucDocTr
                {
                    Items = new List<object>
                    {
                        new StrucDocTd
                        {
                            Text = new List<string> { lstSocials[0]["Description"] }
                        }
                    }
                };

                tbody.tr.Add(bodyTr);

                if (!string.IsNullOrWhiteSpace(lstSocials[0]["IsPatientPregnant"]) && lstSocials[0]["IsPatientPregnant"] != "No - pregnant")
                {
                    var tablePregnant = new StrucDocTable();
                    text.Items.Add(tablePregnant);
                    tablePregnant.border = "1";
                    tablePregnant.width = "100%";
                    tablePregnant.thead = new StrucDocThead { tr = new List<StrucDocTr>() };
                    var headerPregnantTr = new StrucDocTr();
                    tablePregnant.thead.tr.Add(headerPregnantTr);
                    headerPregnantTr.Items = new List<object>
                    {
                        new StrucDocTh {Text = new List<string> {"Is patient pregnant"}},
                        new StrucDocTh {Text = new List<string> {"(If yes) Estimated date of delivery"}},
                    };

                    tablePregnant.tbody = new List<StrucDocTbody>();
                    var tbodyPregnant = new StrucDocTbody();
                    tablePregnant.tbody.Add(tbodyPregnant);

                    tbodyPregnant.tr = new List<StrucDocTr>();

                    var bodyPregnantTr = new StrucDocTr
                    {
                        Items = new List<object>
                        {
                            new StrucDocTd
                            {
                                Text = new List<string> { lstSocials[0]["IsPatientPregnant"] }
                            },
                             new StrucDocTd
                            {
                                Text = new List<string> { lstSocials[0]["EDD"] }
                            }
                        }
                    };

                    tbodyPregnant.tr.Add(bodyPregnantTr);
                }

                #region Patient Residence

                var patientResidenceEntry = new Entry();
                socialHistoryComponent.section.entry.Add(patientResidenceEntry);
                var patientResidenceObservation = new Observation();
                patientResidenceEntry.Item = patientResidenceObservation;

                patientResidenceObservation.classCode = "OBS";
                patientResidenceObservation.moodCode = x_ActMoodDocumentObservation.EVN;
                patientResidenceObservation.templateId = new List<II>()
                {
                    new II { root = "2.16.840.1.113883.10.20.34.3.25" }
                };

                patientResidenceObservation.id = new List<II> { new II { root = Guid.NewGuid().ToString() } };

                patientResidenceObservation.code = new CD
                {
                    code = "75617-1",
                    codeSystem = "2.16.840.1.113883.6.1",
                    displayName = "Residence",
                    codeSystemName = "LOINC"
                };

                patientResidenceObservation.statusCode = new CS
                {
                    code = "completed"
                };
                patientResidenceObservation.value = new List<ANY>()
                {
                    new CD
                    {
                        code = "264362003",
                        codeSystem = "2.16.840.1.113883.6.96",
                        displayName = "Private home",
                        codeSystemName= "SNOMED CT"
                    }
                };

                #endregion Patient Residence

                #region Smoking History
                foreach (var item in lstSocials)
                {

                    var smokingHistoryEntry = new Entry();
                    socialHistoryComponent.section.entry.Add(smokingHistoryEntry);
                    var smokingHistoryObservation = new Observation();
                    smokingHistoryEntry.Item = smokingHistoryObservation;

                    smokingHistoryObservation.classCode = "OBS";
                    smokingHistoryObservation.moodCode = x_ActMoodDocumentObservation.EVN;
                    smokingHistoryObservation.templateId = new List<II>()
                    {
                        new II { root = "2.16.840.1.113883.10.20.22.4.85" }
                    };

                    smokingHistoryObservation.id = new List<II> { new II { root = Guid.NewGuid().ToString() } };

                    smokingHistoryObservation.code = new CD
                    {
                        code = "11367-0",
                        codeSystem = "2.16.840.1.113883.6.1",
                        displayName = "History of tobacco use",
                        codeSystemName = "LOINC"
                    };

                    smokingHistoryObservation.statusCode = new CS
                    {
                        code = "completed"
                    };
                    smokingHistoryObservation.value = new List<ANY>()
                    {
                        new CD
                        {
                            code = item["SNOMEDID"],
                            codeSystem = "2.16.840.1.113883.6.96",
                            displayName = item["Description"],
                            codeSystemName= "SNOMED CT"
                        }
                    };

                }
                #endregion Smoking History

                #region Smoking Status
                var smokingStatusEntry = new Entry();
                socialHistoryComponent.section.entry.Add(smokingStatusEntry);
                var smokingStatusObservation = new Observation();
                smokingStatusEntry.Item = smokingStatusObservation;
                smokingStatusObservation.classCode = "OBS";
                smokingStatusObservation.moodCode = x_ActMoodDocumentObservation.EVN;
                smokingStatusObservation.templateId = new List<II>()
                {
                    new II { root = "2.16.840.1.113883.10.20.22.4.78" }
                };
                smokingStatusObservation.code = new CD
                {
                    code = "72166-2",
                    codeSystem = "2.16.840.1.113883.6.1",
                    displayName = "Tobacco smoking status NHIS"
                };
                smokingStatusObservation.statusCode = new CS
                {
                    code = "completed"
                };
                smokingStatusObservation.effectiveTime = new IVL_TS { value = DateTime.Now.ToString("yyyy") };
                smokingStatusObservation.value = new List<ANY>();
                var snomedid = lstSocials[0]["SNOMEDID"];
                if (!string.IsNullOrWhiteSpace(snomedid))
                {
                    smokingStatusObservation.value.Add(new CD
                    {
                        code = snomedid,
                        codeSystem = "2.16.840.1.113883.6.96",
                        displayName = MDVUtility.ToStr(lstSocials[0]["SmokingStatus"])
                    });
                }
                else
                {
                    smokingStatusObservation.value.Add(new CD
                    {
                        code = "266927001",
                        codeSystem = "2.16.840.1.113883.6.96",
                        displayName = "Unknown if ever smoked"
                    });
                }
                #endregion Smoking Status

                #region Is Female Pregnant
                if (lstSocials[0]["Description"] == "")
                {
                    var pregnantsEntry = new Entry();
                    socialHistoryComponent.section.entry.Add(pregnantsEntry);
                    var pregnantsObservation = new Observation();
