                    },
                    statusCode = new CS
                    {
                        code = "completed"
                    },
                    effectiveTime = new IVL_TS
                    {
                        ItemsElementName = new[] { ItemsChoiceType2.low, ItemsChoiceType2.high },
                        Items = new QTY[] { new IVXB_TS { nullFlavor = "NI" }, new IVXB_TS { nullFlavor = "NI" } }
                    },
