                        },
                        id = new List<II>
                        {
                            new II {root=Guid.NewGuid().ToString(),assigningAuthorityName="GroupIdentifier"}
                        },
                        code = new CD(),
                        statusCode = new CS
                        {
                            code = "completed"
                        },
                        priorityCode = new CE
                        {
                            code = drItem["Priority"],
                            displayName = HelperMethods.GetPriority(drItem["Priority"]),
                            codeSystem = "Example"
                        },
                    };
                    var performer = new Performer2();
                    var ae = new AssignedEntity
                    {
                        id = new List<II>()
