                        //{
                        //    new IVXB_TS { value = HelperMethods.SetDateTime(DateTime.Now) },
                        //    new IVXB_TS { value = HelperMethods.SetDateTime(DateTime.Now) }
                        //}
                    }

                };
            }
            return address;
        }

        public static PN SetName(string use, string familyName, List<string> givenNames, string prefix = "", string suffix = "", string previousName = "")
        {
            var name = new PN();
            if (!string.IsNullOrWhiteSpace(use))
                name.use = new List<string> { use };
            name.Items = new List<ENXP>();
            if (!string.IsNullOrWhiteSpace(familyName))
                name.Items.Add(new enfamily { Text = new List<string> { familyName } });

            if (givenNames != null && givenNames.Count > 0)
            {
                foreach (var nam in givenNames.Where(nam => !string.IsNullOrWhiteSpace(nam)))
                {
                    if (previousName != "" && givenNames.IndexOf(nam) == 0)
                        name.Items.Add(new engiven { Text = new List<string> { nam }, qualifier = new List<string> { "BR" } });
                    else
                        name.Items.Add(new engiven { Text = new List<string> { nam } });
                }
            }
            if (!string.IsNullOrWhiteSpace(prefix))
                name.Items.Add(new enprefix { Text = new List<string> { prefix } });

            if (!string.IsNullOrWhiteSpace(suffix))
                name.Items.Add(new ensuffix { Text = new List<string> { suffix } });
            return name;
        }

        public static PN SetNameWithNodes(string use, string familyName, List<string> givenNames, string prefix = "", string suffix = "", string previousName = "")
        {
            var name = new PN();
            if (!string.IsNullOrWhiteSpace(use))
                name.use = new List<string> { use };
            name.Items = new List<ENXP>();
            if (!string.IsNullOrWhiteSpace(familyName))
                name.Items.Add(new enfamily { Text = new List<string> { familyName } });
            else
                name.Items.Add(new enfamily { Text = new List<string> { "" } });

            if (givenNames != null && givenNames.Where(nam => !string.IsNullOrWhiteSpace(nam)).ToList().Count > 0)
            {
                foreach (var nam in givenNames.Where(nam => !string.IsNullOrWhiteSpace(nam)))
                {
                    if (previousName != "" && givenNames.IndexOf(nam) == 0)
                        name.Items.Add(new engiven { Text = new List<string> { nam }, qualifier = new List<string> { "BR" } });
                    else
                        name.Items.Add(new engiven { Text = new List<string> { nam } });
                }
            }
            else
            {
                name.Items.Add(new engiven { Text = new List<string> { "" } });
            }
            if (!string.IsNullOrWhiteSpace(prefix))
                name.Items.Add(new enprefix { Text = new List<string> { prefix } });

            if (!string.IsNullOrWhiteSpace(suffix))
                name.Items.Add(new ensuffix { Text = new List<string> { suffix } });
            return name;
        }
        public static string ConvertlbsToKG(string lbs)
        {
            string kg = "";
            if (!string.IsNullOrWhiteSpace(lbs))
            {
                kg = MDVUtility.ToStr(Math.Round(Convert.ToDouble(lbs) * 0.453592));
            }

            return kg;
        }

        public static string ConvertInchToCm(string inch)
        {
            //string inch;
            //if (feet.IndexOf(".", StringComparison.Ordinal) > -1)
            //{
            //    var feetarr = feet.Split('.');
            //    inch = feetarr.Count() > 1 ? MDVUtility.ToStr((MDVUtility.ToInt32(feetarr[0]) * 12) + MDVUtility.ToInt32(feetarr[1])) : MDVUtility.ToStr(MDVUtility.ToInt32(feetarr[0]) * 12);
            //}
            //else
            //    inch = MDVUtility.ToStr(MDVUtility.ToInt32(feet) * 12);
            string cm = string.IsNullOrWhiteSpace(inch) ? "" : MDVUtility.ToStr(Math.Round(Convert.ToDouble(inch) * 2.54));
            return cm;
        }
        public static string GetGenderCode(string gender)
        {
            switch (gender.ToLower())
            {
                case "male":
                    return "M";
                case "female":
                    return "F";
                default:
                    return "UN";
            }
        }

        public static string GetMaritalStatusCode(string maritalStatus)
        {
            string returnVal = string.Empty;
            if (maritalStatus.ToLower() == "divorced")
                returnVal = "D";
            else if (maritalStatus.ToLower() == "married")
                returnVal = "M";
            else if (maritalStatus.ToLower() == "partner")
                returnVal = "P";
            else if (maritalStatus.ToLower() == "single")
                returnVal = "S";
            else if (maritalStatus.ToLower() == "unknown")
                returnVal = "S";
            else if (maritalStatus.ToLower() == "widowed")
                returnVal = "W";
            else if (maritalStatus.ToLower() == "legally separated")
                returnVal = "L";
            return returnVal;
        }

        public static string GetCompletionStatusOfImmunization(string code)
        {
            var returnVal = string.Empty;
            switch (code.ToLower())
            {
                case "cp":
                    returnVal = "Complete";
                    break;
                case "re":
                    returnVal = "Refused";
                    break;
                case "na":
                    returnVal = "Not Administered";
                    break;
                case "pa":
                    returnVal = "Partially Administered";
                    break;
            }
            return returnVal;
        }

        public static Component3 IntializeComponent3(List<string> templatedId, string code, string codeSystem,
            string codeSystemName, string displayName, string title, string assigningAuthorityName = "")
        {
            var comp3 = new Component3 { section = new Section() };
            if (templatedId.Count > 0)
            {
                comp3.section.templateId = new List<II>();

                foreach (string t in templatedId)
                {
                    if (!string.IsNullOrWhiteSpace(t) && string.IsNullOrWhiteSpace(assigningAuthorityName))
                    {
                        comp3.section.templateId.Add(new II { root = t });
                    }
                    else if (!string.IsNullOrWhiteSpace(t) && !string.IsNullOrWhiteSpace(assigningAuthorityName))
                    {
                        comp3.section.templateId.Add(new II { root = t, assigningAuthorityName = assigningAuthorityName });
                    }
                    else
                    {
                        return null;
                    }
                }
            }
            else
                return null;
            if (!string.IsNullOrWhiteSpace(code) && !string.IsNullOrWhiteSpace(codeSystem) &&
                !string.IsNullOrWhiteSpace(codeSystemName) && !string.IsNullOrWhiteSpace(displayName))
            {
                comp3.section.code = new CE
                {
                    code = code,
                    codeSystem = codeSystem,
                    codeSystemName = codeSystemName,
                    displayName = displayName,
                };
            }
            else
                return null;
            if (!string.IsNullOrWhiteSpace(title))
                comp3.section.title = new ST { Text = new List<string> { title } };
            else
                return null;
            comp3.section.text = new StrucDocText { Items = new List<object>() };
            return comp3;
        }
        public static string GetPriority(string priority)
        {
            switch (priority)
            {
                case "1":
                    priority = "Primary";
                    break;
                case "2":
                    priority = "Secondary";
                    break;
                case "3":
                    priority = "Tertiary";
                    break;
                case "4":
                    priority = "Quaternary";
                    break;
                case "5":
                    priority = "Quinary";
                    break;
                case "6":
                    priority = "Senary";
                    break;
                case "7":
                    priority = "Septenary";
                    break;
                case "8":
                    priority = "Octonary";
                    break;
                case "9":
                    priority = "Nonary";
                    break;
                case "10":
                    priority = "Denary";
                    break;
                default:
                    break;
            }
            return priority;
        }
        public static CPTLookupModel GetCPT(string cptcCOde)
        {
            CPTLookupModel cptData = new CPTLookupModel();
            string jsonData = new Business.BLL.BLLIMO().SearchCPTCode(cptcCOde);
            System.Web.Script.Serialization.JavaScriptSerializer ser = new System.Web.Script.Serialization.JavaScriptSerializer();
            var SearchedfieldsJSON = ser.Deserialize<dynamic>(jsonData);
            var itemArray = SearchedfieldsJSON["data"]["items"];
            foreach (var item in itemArray)
            {
                var DatakeyValues = new CPTLookupModel
                {
                    CPTCodeDescription = MDVUtility.ToStr(item["title"]),
                    CPTCode = MDVUtility.ToStr(item["CPT_CODE"]),
                    SNOMEDID = MDVUtility.ToStr(item["SCT_CONCEPT_ID"]),
                    SNOMEDDescription = MDVUtility.ToStr(item["SNOMED_DESCRIPTION"]),

                };
                cptData = DatakeyValues;
                if (!string.IsNullOrWhiteSpace(MDVUtility.ToStr(item["SCT_CONCEPT_ID"]))
                    && !string.IsNullOrWhiteSpace(MDVUtility.ToStr(item["SNOMED_DESCRIPTION"])))
                {
                    break;
                }
            }
            return cptData;
        }
        public static string ConvertTempFtoC(string tempInF)
        {
            string temInC = "";
            if (!string.IsNullOrWhiteSpace(tempInF))
            {
                var temp = Convert.ToDouble(tempInF) * (38 / 100.4);
                temInC = MDVUtility.ToStr(Math.Round(temp));
            }
            return temInC;
        }
        public static string GetNewGUIDFromId(long id)
        {
            string guid = "";
            byte[] bytes = new byte[16];
            BitConverter.GetBytes(id).CopyTo(bytes, 0);
            guid = new Guid(bytes).ToString();
            return guid;
        }

        public static string GetGenderFromRelationship(string Relationship)
        {
            if (!string.IsNullOrWhiteSpace(Relationship))
            {
                List<LisValues> MaleList = new List<LisValues>
                {
                    new LisValues { Description = "Father" },new LisValues { Description = "Brother" },new LisValues { Description = "Son" },
                    new LisValues { Description = "Maternal Uncle" },new LisValues { Description = "Maternal Grand Father" },
                    new LisValues { Description = "Paternal Grand Father" },new LisValues { Description = "Maternal Great Uncle" },
                    new LisValues { Description = "Paternal Great Uncle" }, new LisValues { Description = "Maternal Great Grandfather" },new LisValues { Description = "Paternal Great Grandfather" }
                };
                List<LisValues> FemaleList = new List<LisValues>
                {
                    new LisValues { Description = "Mother" },new LisValues { Description = "Sister" },new LisValues { Description = "Daughter" },
                    new LisValues { Description = "Maternal Aunt" },new LisValues { Description = "Paternal Aunt" },new LisValues { Description = "Maternal Grand Mother" },
                    new LisValues { Description = "Paternal Grand Mother" },new LisValues { Description = "Maternal Great Aunt" },new LisValues { Description = "Paternal Great Aunt" },
                    new LisValues { Description = "Maternal Great Grandmother" },new LisValues { Description = "Paternal Great Grandmother" }
                };
                if (MaleList.FirstOrDefault(m => m.Description == Relationship) != null)
                {
                    return "Male";
                }
                else if (FemaleList.FirstOrDefault(m => m.Description == Relationship) != null)
                {
                    return "Female";
                }
                else if (Relationship == "Unknown")
                {
                    return "Unknown";
                }
                else
                {
                    return "Unknown";
                }
            }
            else
            {
                return "UNK";
            }
        }

        public static string GetComponentName(List<Component> ComponentList, string ComponentName)
        {
            List<LisValues> ComponentsList = new List<LisValues>
            {
                new LisValues { Description = "SmokingStatusDataElement" },new LisValues { Description = "ProblemDataElement" },
                new LisValues { Description = "MedicationDataElement" },
                new LisValues { Description = "PlanOfCareDataElement" },new LisValues { Description = "MedicalEquipmentDataElement" },
                new LisValues { Description = "PlanofTreatmentDataElement" },new LisValues { Description = "VitalSignDataElement" },
                new LisValues { Description = "AssessmentDataElement" },new LisValues { Description = "LabResultDataElement" },
                new LisValues { Description = "ImmunizationDataElement" },new LisValues { Description = "HealthConcernsDataElement" },
                new LisValues { Description = "AllergiesDataElement" },new LisValues { Description = "Interventions" },
                new LisValues { Description = "CareTeamMembersDataElement" },new LisValues { Description = "CarePlanOutcomes" },
                new LisValues { Description = "ProceduresDataElement" }
            };
            LisValues objComponent = ComponentsList.FirstOrDefault(m => m.Description.ToLower().IndexOf("aroreport") > -1);

            if (objComponent == null)
            {
                return string.Empty;
            }
            else
            {
                return objComponent.Description;
            }
        }

        public static string getInterPretationCode(string flag)
        {
            string code = "UNK";
            if (!string.IsNullOrWhiteSpace(flag))
            {
                switch (flag.ToLower())
                {
                    case "abnormal":
                        code = "A";
                        break;
                    case "better":
                        code = "B";
                        break;
                    case "normal":
                        code = "N";
                        break;
                    case "intermediate":
                        code = "I";
                        break;
                    case "indeterminate":
                        code = "IND";
                        break;
                    case "non-susceptible":
                        code = "NS";
                        break;
                    case "not tested":
                        code = "N";
                        break;
                    default:
                        break;
                }
            }

            return code;
        }
    }

    public class LisValues
    {
        public string Description { get; set; }
    }
